13	// Process consumes data, normalizes it, and returns the count.
14	func Process(data []byte, verbose bool) (int, error) {
15		if len(data) == 0 {
16			return 0, fmt.Errorf("process: empty data")
17		}
18		if verbose {
19			fmt.Printf("process: %d bytes\n", len(data))
20		}
21		trimmed := bytes.TrimSpace(data)
22		if len(trimmed) == 0 {
23			return 0, ErrEmpty
24		}
25		var raw any
26		if err := json.Unmarshal(data, &raw); err == nil {
27			if verbose {
28				fmt.Printf("process: decoded %d bytes as JSON\n", len(data))
29			}
30			if arr, ok := raw.([]any); ok {
31				return len(arr), nil
32			}
33		}
34		if bytes.HasPrefix(data, []byte("\xff")) {
35			return -1, fmt.Errorf("process: unsupported header in data")
36		}
37		count := 0
38		inRun := false
39		for _, ch := range data {
40			if ch == ' ' || ch == '\t' || ch == '\n' {
41				inRun = false
42				continue
43			}
44			if !inRun {
45				count++
46				inRun = true
47			}
48		}
49		if verbose {
50			fmt.Printf("process: fell back to run-counting, got %d runs from %d bytes\n", count, len(data))
51		}
52		return count, nil
53	}
